import{_ as n,c as a,a1 as r,o as e}from"./chunks/framework.BDxlaA_J.js";const u=JSON.parse('{"title":"Sử dụng ZAP (Zed Attack Proxy)","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/10-session-hijacking/1-Using-ZAP.md","filePath":"vi/categories/ethical-hacking-labs/10-session-hijacking/1-Using-ZAP.md"}'),o={name:"vi/categories/ethical-hacking-labs/10-session-hijacking/1-Using-ZAP.md"};function s(i,t,c,g,h,p){return e(),a("div",null,t[0]||(t[0]=[r('<h1 id="su-dung-zap-zed-attack-proxy" tabindex="-1">Sử dụng ZAP (Zed Attack Proxy) <a class="header-anchor" href="#su-dung-zap-zed-attack-proxy" aria-label="Permalink to &quot;Sử dụng ZAP (Zed Attack Proxy)&quot;">​</a></h1><p>Zed Attack Proxy (ZAP) là một công cụ kiểm thử xâm nhập miễn phí, mã nguồn mở được bảo trì dưới sự quản lý của dự án Open Web Application Security Project (OWASP). ZAP được thiết kế đặc biệt để kiểm thử ứng dụng web và có tính linh hoạt cũng như khả năng mở rộng cao.</p><p align="center"><img src="https://www.zaproxy.org/getting-started/images/browser-no-proxy.png"></p><p>Về bản chất, ZAP là một &quot;man-in-the-middle proxy&quot; (proxy trung gian). Nó nằm giữa trình duyệt của người kiểm thử và ứng dụng web để có thể chặn và kiểm tra các thông điệp được gửi giữa trình duyệt và ứng dụng web, sửa đổi nội dung nếu cần, và sau đó chuyển tiếp các gói tin đó đến đích. Nó có thể được sử dụng như một ứng dụng độc lập hoặc như một tiến trình daemon. <a href="https://www.zaproxy.org/getting-started/" target="_blank" rel="noreferrer">[...]</a></p><p><a href="https://www.zaproxy.org/download/" target="_blank" rel="noreferrer">&gt;&gt; Tải ZAP</a></p><h3 id="muc-tieu" tabindex="-1">Mục tiêu <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu&quot;">​</a></h3><ul><li>Chặn lưu lượng truy cập giữa máy chủ và client</li></ul><h3 id="yeu-cau" tabindex="-1">Yêu cầu <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu&quot;">​</a></h3><ul><li>Máy ảo Windows Server 2012 hoặc 2016 (Máy tấn công)</li><li>Máy ảo Windows 10 (Mục tiêu)</li></ul><h2 id="thiet-lap-proxy" tabindex="-1">Thiết lập Proxy <a class="header-anchor" href="#thiet-lap-proxy" aria-label="Permalink to &quot;Thiết lập Proxy&quot;">​</a></h2><ol><li><p>Đăng nhập vào <strong>Windows 10</strong> và khởi động bất kỳ trình duyệt nào, trong lab này sử dụng: <strong>Firefox</strong>.</p></li><li><p>Vào <strong>Settings</strong> &gt; <strong>Network Settings</strong></p></li><li><p>Trong <strong>Proxy Settings</strong>, tích chọn ô <strong>Manual Proxy Configuration</strong>, và nhập địa chỉ IP của máy tấn công vào port <strong>8080</strong> như hình bên dưới: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/f8943de44ef583f07e8046d9eb7a16421feb0a55/zap-0.png" alt="firefox-proxy"></p></li><li><p>Bạn cũng có thể cấu hình trực tiếp trong <strong>Internet Properties</strong> trên <strong>Control Panel</strong> &gt; <strong>Connections Tab</strong> &gt; <strong>LAN Settings</strong><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/f8943de44ef583f07e8046d9eb7a16421feb0a55/zap-7.png" alt="proxy"><strong>Tích chọn checkbox Proxy Server và nhập địa chỉ IP của máy tấn công cùng port 8080</strong> như hình bên dưới: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/f8943de44ef583f07e8046d9eb7a16421feb0a55/zap-8.png" alt="proxy2"></p></li></ol><h2 id="thiet-lap-zap-zed-attack-proxy" tabindex="-1">Thiết lập ZAP (Zed Attack Proxy) <a class="header-anchor" href="#thiet-lap-zap-zed-attack-proxy" aria-label="Permalink to &quot;Thiết lập ZAP (Zed Attack Proxy)&quot;">​</a></h2><p>Chuyển sang máy tấn công (Windows Server).</p><p>Lưu ý: Đảm bảo đã cài đặt <strong>Java Runtime</strong></p><ol><li><p>Tải ZAP &gt; <a href="https://www.zaproxy.org/download/" target="_blank" rel="noreferrer">https://www.zaproxy.org/download/</a></p></li><li><p>Trong quá trình cài đặt, đảm bảo chọn tùy chọn: <strong>&quot;No, I do not want to persist this session at this moment in time&quot;</strong>: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/f8943de44ef583f07e8046d9eb7a16421feb0a55/zap-1.png" alt="zap1"></p></li><li><p>Trên cửa sổ chính OWASP ZAP, nhấp vào biểu tượng <strong>&quot;+&quot;</strong> ở ngăn bên phải, sau đó thêm tab <strong>Break</strong>, như hình bên dưới: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/f8943de44ef583f07e8046d9eb7a16421feb0a55/zap-2.png" alt="zap-main-window"> Tab <strong>Break</strong> cho phép bạn <strong>sửa đổi response</strong> hoặc <strong>request</strong> khi nó bị ZAP chặn. Nó cũng cho phép bạn sửa đổi một số phần tử mà bạn không thể sửa đổi qua trình duyệt; bao gồm: <strong>Header, các trường ẩn, các trường bị vô hiệu hóa, các trường sử dụng Javascript để lọc ký tự bất hợp pháp</strong>.</p></li><li><p>Khi tab <strong>Break</strong> đã được thêm, bạn cần cấu hình ZAP để hoạt động như một proxy, vào <strong>Options</strong> bằng cách nhấp vào biểu tượng <strong>bánh răng</strong> ở phía trên, như hình bên dưới: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/f8943de44ef583f07e8046d9eb7a16421feb0a55/zap-3.png" alt="zap-options"></p></li><li><p>Trong cửa sổ <strong>Options</strong>, chọn <strong>Local Proxies</strong> từ ngăn bên trái; Địa chỉ là <strong>địa chỉ IP của Windows Server</strong> và port mặc định là <strong>8080</strong>: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/f8943de44ef583f07e8046d9eb7a16421feb0a55/zap-4.png" alt="zap-options-2"></p></li><li><p>Quay lại <strong>cửa sổ chính ZAP</strong> và nhấp vào <strong>Nút màu Xanh lá (Set break on all requests and responses)</strong> như hình bên dưới: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/f8943de44ef583f07e8046d9eb7a16421feb0a55/zap-5.png" alt="zap-green-icon"> Nút này thiết lập và hủy breakpoint toàn cục sẽ bắt và hiển thị response hoặc request tiếp theo trong tab Break từ máy mục tiêu. Bạn có thể sửa đổi bất kỳ phần nào của request hoặc response mà bạn muốn và gửi nó đến ứng dụng nạn nhân bằng cách nhấp vào <strong>Step</strong> hoặc <strong>Continue</strong>. Ngoài ra, bạn có thể nhấp <strong>Drop</strong> để loại bỏ request hoặc response.</p></li></ol><hr><ol><li><p><strong>Chuyển lại sang máy mục tiêu (Windows 10)</strong> và khởi động trình duyệt mà bạn đã cấu hình proxy.</p></li><li><p>Nhập URL: www.certifiedhacker.com , nếu bạn nhận được thông báo cảnh báo nào thì hãy chấp nhận rủi ro và tiếp tục.</p></li><li><p>Bây giờ, <strong>chuyển sang máy tấn công (Windows Server)</strong>, bạn sẽ thấy rằng proxy ZAP đã bắt đầu chụp các request từ mục tiêu. <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/f8943de44ef583f07e8046d9eb7a16421feb0a55/zap-6.png" alt="zap6"></p></li><li><p>Bây giờ nhấp vào nút <strong>&#39;submit and step to the next request&#39;</strong> cho đến khi bạn chụp được request <strong>GET</strong> của trang web đang duyệt. <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/f8943de44ef583f07e8046d9eb7a16421feb0a55/zap-9.png" alt="zap7"></p></li></ol><p>Bạn có thể sửa đổi tất cả các request GET đã chụp trên <strong>tab Break</strong> và chuyển tiếp lưu lượng đến máy mục tiêu, thay đổi trang web, v.v.</p>',18)]))}const d=n(o,[["render",s]]);export{u as __pageData,d as default};
